    const newGrid = grid.map(row => [...row]);
    const subRows: number[][] = [];

    for (let i = 0; i < k; i++) {
        const row = newGrid[x + i];
        const sub = row.slice(y, y + k);
        subRows.push(sub);
    }

    subRows.reverse();

    for (let i = 0; i < k; i++) {
        const row = newGrid[x + i];
        for (let j = 0; j < k; j++) {
            row[y + j] = subRows[i][j];
        }
    }

    return newGrid;
}

